class Solution:
    def numberOfRightTriangles(self, grid) -> int:
        m, n = len(grid), len(grid[0])
        count = 0
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    for i2 in range(m):
                        if i2 != i and grid[i2][j] == 1:
                            for j2 in range(n):
                                if j2 != j and grid[i][j2] == 1:
                                    count += 1
        return count

solutions.python:
class Solution:
    def numberOfRightTriangles(self, grid) -> int:
        row_cnt = [sum(row) for row in grid]
        col_cnt = [sum(grid[r][c] for r in range(len(grid))) for c in range(len(grid[0]))]
        total = 0
        for i, row in enumerate(grid):
            for j, v in enumerate(row):
                if v == 1:
                    total += (row_cnt[i] - 1) * (col_cnt[j] - 1)
        return total

