var numberOfRightTriangles = function(grid) {
    const m = grid.length, n = grid[0].length;
    const rowCnt = grid.map(row => row.reduce((s, v) => s + v, 0));
    const colCnt = Array(n).fill(0);
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) colCnt[j] += grid[i][j];
    let total = 0;
    for (let i = 0; i < m; i++)
        for (let j = 0; j < n; j++)
            if (grid[i][j] === 1) total += (rowCnt[i] - 1) * (colCnt[j] - 1);
    return total;
};
